-- Script to update existing subjects with proper branch_id values\n-- Run this AFTER adding the new columns\n\n-- Step 1: Check current state\nSELECT 'Current subjects without branch_id:' as info;\nSELECT \n    school_id,\n    COUNT(*) as subject_count,\n    GROUP_CONCAT(DISTINCT section) as sections,\n    GROUP_CONCAT(DISTINCT class_code ORDER BY class_code) as sample_classes\nFROM subjects \nWHERE branch_id IS NULL OR branch_id = ''\nGROUP BY school_id;\n\n-- Step 2: Show available branches\nSELECT 'Available branches in school_locations:' as info;\nSELECT \n    school_id,\n    branch_id,\n    location_name,\n    status,\n    CASE \n        WHEN status = 'Active' THEN '✓ Available'\n        ELSE '✗ Inactive'\n    END as availability\nFROM school_locations \nORDER BY school_id, branch_id;\n\n-- Step 3: Generate automatic update statements\nSELECT 'Suggested UPDATE statements (copy and execute):' as info;\nSELECT CONCAT(\n    'UPDATE subjects SET branch_id = \"', \n    branch_mapping.branch_id, \n    '\" WHERE school_id = \"', \n    branch_mapping.school_id, \n    '\" AND (branch_id IS NULL OR branch_id = \"\");'\n) as suggested_update_statement\nFROM (\n    SELECT \n        school_id,\n        MIN(branch_id) as branch_id  -- Use the first branch for each school\n    FROM school_locations \n    WHERE status = 'Active'\n    GROUP BY school_id\n) branch_mapping\nWHERE branch_mapping.school_id IN (\n    SELECT DISTINCT school_id \n    FROM subjects \n    WHERE branch_id IS NULL OR branch_id = ''\n);\n\n-- Step 4: Option 1 - Automatic update using first active branch per school\n-- UNCOMMENT THE FOLLOWING BLOCK TO EXECUTE AUTOMATIC UPDATE:\n/*\nUPDATE subjects s\nJOIN (\n    SELECT \n        school_id,\n        MIN(branch_id) as default_branch_id\n    FROM school_locations \n    WHERE status = 'Active'\n    GROUP BY school_id\n) sl ON s.school_id = sl.school_id\nSET s.branch_id = sl.default_branch_id\nWHERE s.branch_id IS NULL OR s.branch_id = '';\n*/\n\n-- Step 5: Option 2 - Manual updates for specific schools\n-- UNCOMMENT AND MODIFY AS NEEDED:\n\n-- Example for SCH/1:\n-- UPDATE subjects SET branch_id = 'BRCH00001' WHERE school_id = 'SCH/1' AND (branch_id IS NULL OR branch_id = '');\n\n-- Example for SCH/2:\n-- UPDATE subjects SET branch_id = 'BRCH00002' WHERE school_id = 'SCH/2' AND (branch_id IS NULL OR branch_id = '');\n\n-- Add more UPDATE statements as needed for your schools\n\n-- Step 6: Verification queries\n\n-- Check subjects still without branch_id (should be 0 after updates)\nSELECT 'Subjects still without branch_id (should be 0):' as verification;\nSELECT COUNT(*) as subjects_without_branch_id\nFROM subjects \nWHERE branch_id IS NULL OR branch_id = '';\n\n-- Show distribution of subjects by school and branch\nSELECT 'Subject distribution by school and branch:' as info;\nSELECT \n    s.school_id,\n    s.branch_id,\n    sl.location_name as branch_name,\n    COUNT(*) as subject_count,\n    GROUP_CONCAT(DISTINCT s.section) as sections\nFROM subjects s\nLEFT JOIN school_locations sl ON s.school_id = sl.school_id AND s.branch_id = sl.branch_id\nGROUP BY s.school_id, s.branch_id, sl.location_name\nORDER BY s.school_id, s.branch_id;\n\n-- Show any subjects with invalid branch_id (not in school_locations)\nSELECT 'Subjects with invalid branch_id (should be empty):' as validation;\nSELECT \n    s.school_id,\n    s.branch_id,\n    COUNT(*) as invalid_subjects\nFROM subjects s\nLEFT JOIN school_locations sl ON s.school_id = sl.school_id AND s.branch_id = sl.branch_id\nWHERE s.branch_id IS NOT NULL \nAND s.branch_id != ''\nAND sl.branch_id IS NULL\nGROUP BY s.school_id, s.branch_id;\n\n-- Final success check\nSELECT \n    CASE \n        WHEN COUNT(*) = 0 THEN '✅ SUCCESS: All subjects have valid branch_id values!'\n        ELSE CONCAT('❌ ERROR: ', COUNT(*), ' subjects still need branch_id values!')\n    END as migration_status\nFROM subjects \nWHERE branch_id IS NULL OR branch_id = '';\n\n-- Show sample of updated subjects\nSELECT 'Sample of subjects with branch_id (first 10):' as info;\nSELECT \n    subject_code,\n    subject,\n    school_id,\n    branch_id,\n    section,\n    class_code,\n    status\nFROM subjects \nWHERE branch_id IS NOT NULL AND branch_id != ''\nLIMIT 10;\n"